            </g>
            <line
              x1="242"
              y1="266"
              x2="272"
              y2="266"
              stroke="#d8c39a"
              strokeOpacity="0.18"
              strokeWidth="1"
              strokeDasharray="1 4"
            />
            <circle cx="292" cy="266" r="2.5" fill="#d8c39a" />
          </svg>

          <canvas ref={canvasRef} className="ondo-bottle__pane" aria-hidden="true" />
          <div className="ondo-bottle__frame" aria-hidden="true" />
        </div>
        <figcaption className="ondo-bottle__caption">
          Look through the pane — the glass bends the light it keeps.{" "}
          <span lang="ko" className="ondo-bottle__captionko">
            유리 너머를 보라. 유리는 제 안의 빛을 구부린다.
          </span>
        </figcaption>
      </figure>
    </section>
  );
}

"use client";

import { useEffect, useRef } from "react";
import type { KeyboardEvent, PointerEvent as ReactPointerEvent } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

type Stop = { offset: string; color: string; opacity: number };

type Scent = {
  id: string;
  temp: string;
  tempKo: string;
  name: string;
  nameKo: string;
  line: string;
  lineKo: string;
  /** 0 = coldest … 1 = warmest; sets the gradation line in the swatch. */
  level: number;
  dir: "v" | "h";
  stops: Stop[];
};

/** Five readings — every scent is a temperature, taken once. */
const SCENTS: Scent[] = [
  {
    id: "body",
    temp: "36.5°",
    tempKo: "36.5도",
    name: "Body",
    nameKo: "체온",
    line: "skin, remembered at its own warmth.",
    lineKo: "제 온기로 기억되는 피부.",
    level: 0.52,
    dir: "v",
    stops: [
      { offset: "0%", color: "#16130f", opacity: 0 },
      { offset: "55%", color: "#d8c39a", opacity: 0.34 },
      { offset: "100%", color: "#9c6b3f", opacity: 0.78 },
    ],
  },
  {
    id: "snow",
    temp: "−2°",
    tempKo: "영하 2도",
    name: "First Snow",
    nameKo: "초설",
    line: "first snow holds its breath over the river.",
    lineKo: "첫눈이 강 위에서 숨을 참는다.",
    level: 0.12,
    dir: "v",
    stops: [
      { offset: "0%", color: "#efe9df", opacity: 0.5 },
      { offset: "45%", color: "#efe9df", opacity: 0.12 },
      { offset: "100%", color: "#efe9df", opacity: 0 },
    ],
  },
  {
    id: "dawn",
    temp: "17°",
    tempKo: "17도",
    name: "Dawn Window",
    nameKo: "새벽 창",
    line: "a window opens before the city wakes.",
    lineKo: "도시가 깨기 전, 창이 먼저 열린다.",
    level: 0.3,
    dir: "h",
    stops: [
      { offset: "0%", color: "#efe9df", opacity: 0.3 },
      { offset: "55%", color: "#16130f", opacity: 0 },
      { offset: "100%", color: "#d8c39a", opacity: 0.14 },
    ],
  },
  {
    id: "ondol",
    temp: "45°",
    tempKo: "45도",
    name: "Ondol",
    nameKo: "온돌",
    line: "the floor keeps yesterday’s fire.",
    lineKo: "바닥은 어제의 불을 기억한다.",
    level: 0.72,
    dir: "v",
    stops: [
      { offset: "0%", color: "#16130f", opacity: 0 },
      { offset: "62%", color: "#9c6b3f", opacity: 0.4 },
      { offset: "100%", color: "#9c6b3f", opacity: 0.92 },
    ],
  },
  {
    id: "pour",
    temp: "62°",
    tempKo: "62도",
    name: "First Pour",
    nameKo: "찻김",
    line: "steam climbs from the first cup.",
