"use client";

import { useEffect, useRef } from "react";

/** The intro opens the wordmark to this fraction of full air on its own. */
const INTRO_FLOOR = 0.45;
/** How long the intro takes to reach the floor. */
const INTRO_MS = 2600;
/** Scroll completes the breath within the first ~0.7 viewport. */
const SCROLL_SPAN = 0.7;
/** Per-frame lerp toward the target, normalized to 60fps in the loop. */
const BREATH_LERP = 0.055;

/**
 * Drives `--ondo-breath` (0 → 1) on the referenced element — the hero
 * wordmark's letter-spacing "breath". The CSS default is 1 (fully airy), so
 * without JavaScript, and under reduced motion, the wordmark simply rests
 * open. With motion allowed, the value starts at 0 (tight, 0.02em apparent
 * tracking), eases to INTRO_FLOOR on its own, and scroll takes it the rest
 * of the way — lerped every frame so it never snaps, capped at 1.
 *
 * The rAF loop only runs while the element is near the viewport and the tab
 * is visible.
 */
export function useBreath<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    if (disabled) {
      // Reduced motion: settle airy, no animation.
      el.style.setProperty("--ondo-breath", "1");
      return;
    }

    el.style.setProperty("--ondo-breath", "0");

    let raf = 0;
    let running = false;
    let inView = true;
    let value = 0;
    let last = 0;
    const born = performance.now();
    const easeOut = (u: number) => 1 - (1 - u) ** 3;

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 48);
      last = now;
      const intro =
        easeOut(Math.min((now - born) / INTRO_MS, 1)) * INTRO_FLOOR;
      const scroll = Math.min(
        window.scrollY / (window.innerHeight * SCROLL_SPAN),
        1,
      );
      const target = Math.max(intro, scroll);
      value += (target - value) * BREATH_LERP * (dt / 16.7);
      if (value > 1) value = 1;
      el.style.setProperty("--ondo-breath", value.toFixed(4));
    };

    const start = () => {
      if (running) return;
      running = true;
      last = performance.now();
      raf = requestAnimationFrame(step);
    };
    const stop = () => {
      running = false;
      cancelAnimationFrame(raf);
    };

    const io = new IntersectionObserver((hits) => {
      inView = hits[hits.length - 1].isIntersecting;
      if (inView && !document.hidden) start();
      else stop();
    });
    io.observe(el);

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      stop();
      io.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. Pre-reveal states (opacity/translate for
 * "fade", the inset clip for "clip") live in styles.css and are gated behind
 * the `.ondo-js` root class, so all content is fully visible when JavaScript
 * never runs.
 *
 * Elements that intersect in the same observer batch are staggered 90ms
 * apart. The delay is written both as transition-delay (for the element
 * itself) and as the `--ondo-reveal-delay` custom property, so a child —
 * the clip-path on a card's art — can inherit the same beat.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          const delay = `${batch * 90}ms`;
          el.style.transitionDelay = delay;
          el.style.setProperty("--ondo-reveal-delay", delay);
          el.classList.add("is-visible");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

