 */
.ondo-bottle__stage {
  --ondo-pane-x: 12%;
  --ondo-pane-top: 7%;
  --ondo-pane-bottom: 10%;
  position: relative;
  width: min(78vw, 440px);
  aspect-ratio: 360 / 560;
  margin-inline: auto;
  background-color: var(--ondo-noir-2);
  border: 1px solid var(--ondo-hairline);
}

.ondo-bottle__svg {
  display: block;
  width: 100%;
  height: 100%;
}

.ondo-bottle__pane {
  position: absolute;
  left: var(--ondo-pane-x);
  right: var(--ondo-pane-x);
  top: var(--ondo-pane-top);
  bottom: var(--ondo-pane-bottom);
  display: block;
  opacity: 0;
}

/* The pane only appears once the first warped frame has been drawn. */
.ondo-js .ondo-bottle__pane.is-live {
  opacity: 1;
  transition: opacity 900ms var(--ondo-ease-air);
}

/* Hairline frame + a static sheen: the sheet of glass is a real object,
   visible (empty) even before JS, honest about its own edges. */
.ondo-bottle__frame {
  position: absolute;
  left: var(--ondo-pane-x);
  right: var(--ondo-pane-x);
  top: var(--ondo-pane-top);
  bottom: var(--ondo-pane-bottom);
  border: 1px solid var(--ondo-hairline-strong);
  background: linear-gradient(
    112deg,
    rgba(239, 233, 223, 0.05) 0%,
    rgba(239, 233, 223, 0) 34%
  );
  pointer-events: none;
}

.ondo-bottle__caption {
  max-width: 30rem;
  margin: 2.2rem auto 0;
  font-size: 0.92rem;
  letter-spacing: 0.04em;
  color: var(--ondo-cream);
}

.ondo-bottle__captionko {
  display: block;
  margin-top: 0.3rem;
  color: var(--ondo-champagne-dim);
}

/* ==========================================================================
   02 · The collection — horizontal rail, clip-path reveals
   ========================================================================== */

.ondo-collection {
  padding: clamp(84px, 12vh, 150px) 0;
}

.ondo-rail {
  overflow-x: auto;
  overscroll-behavior-x: contain;
  scroll-snap-type: x proximity;
  padding: 0.5rem clamp(20px, 6vw, 72px) 1.6rem;
  scrollbar-width: thin;
  scrollbar-color: var(--ondo-hairline-strong) transparent;
}

.ondo-rail:focus-visible {
  outline-offset: -4px;
}

.ondo-js .ondo-rail {
  cursor: grab;
}

.ondo-js .ondo-rail.is-dragging {
  cursor: grabbing;
  user-select: none;
  scroll-snap-type: none;
}

.ondo-rail__list {
  display: flex;
  gap: clamp(18px, 3vw, 36px);
  width: max-content;
  margin: 0;
  padding: 0;
  list-style: none;
}

.ondo-card {
  flex: none;
  width: clamp(230px, 62vw, 300px);
  scroll-snap-align: start;
}

.ondo-card__art {
  aspect-ratio: 280 / 340;
  border: 1px solid var(--ondo-hairline);
}

.ondo-card__svg {
  display: block;
  width: 100%;
  height: 100%;
}

.ondo-card__body {
  padding-top: 1.1rem;
}

.ondo-card__temp {
  margin: 0;
  font-family: var(--ondo-font-display);
  font-weight: 400;
  font-size: 1.7rem;
  line-height: 1.15;
  letter-spacing: 0.1em;
  color: var(--ondo-champagne);
}

.ondo-card__tempko {
  margin-left: 0.3em;
  font-size: 0.55em;
  color: var(--ondo-champagne-dim);
}

.ondo-card__name {
  margin: 0.45rem 0 0.7rem;
  font-size: 0.78rem;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--ondo-cream);
}

.ondo-card__nameko {
  margin-left: 0.4em;
  text-transform: none;
  letter-spacing: 0.1em;
  color: var(--ondo-champagne-dim);
}

.ondo-card__line {
  margin: 0;
  font-size: 0.92rem;
  color: var(--ondo-cream);
}

.ondo-card__line:lang(ko) {
  margin-top: 0.15rem;
  color: var(--ondo-champagne-dim);
}

.ondo-rail__hint {
  max-width: 880px;
  margin: 1.4rem auto 0;
  padding-inline: clamp(20px, 6vw, 72px);
  font-size: 0.72rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--ondo-champagne-dim);
}

/* ==========================================================================
   03 · The note — composition ledger
   ========================================================================== */

.ondo-notes {
  padding: clamp(84px, 12vh, 150px) 0;
}

.ondo-tiers {
  max-width: 880px;
  margin: 0 auto;
  padding-inline: clamp(20px, 6vw, 72px);
}

.ondo-tier {
  display: grid;
  grid-template-columns: 1fr;
  gap: 0.15rem 2rem;
  padding: clamp(1.5rem, 3.5vh, 2.4rem) 0;
  border-top: 1px solid var(--ondo-hairline);
}

.ondo-tier:last-of-type {
  border-bottom: 1px solid var(--ondo-hairline);
}

.ondo-tier__name {
  font-family: var(--ondo-font-display);
  font-size: 1.25rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: var(--ondo-champagne);
}

.ondo-tier__nameko {
  margin-left: 0.35em;
  font-size: 0.7em;
  text-transform: none;
  letter-spacing: 0.1em;
  color: var(--ondo-champagne-dim);
}

.ondo-tier__notes {
  margin: 0;
  letter-spacing: 0.05em;
  color: var(--ondo-cream);
}

.ondo-tier__notes--ko {
  color: var(--ondo-champagne-dim);
}

@media (min-width: 760px) {
  .ondo-tier {
    grid-template-columns: 11rem 1fr;
  }

  .ondo-tier__name {
    grid-row: 1 / span 2;
  }

  .ondo-tier__notes,
  .ondo-tier__notes--ko {
    grid-column: 2;
  }
}

.ondo-credo {
  max-width: 640px;
  margin: clamp(3.5rem, 8vh, 5.5rem) auto 0;
  padding-inline: clamp(20px, 6vw, 72px);
  text-align: center;
}

.ondo-credo__en {
  margin: 0;
  font-family: var(--ondo-font-display);
  font-size: clamp(1.2rem, 2.6vw, 1.6rem);
  line-height: 1.55;
  letter-spacing: 0.06em;
  color: var(--ondo-cream);
}

.ondo-credo__ko {
  margin: 0.6rem 0 2rem;
  color: var(--ondo-champagne-dim);
}

.ondo-credo__ko:last-child {
  margin-bottom: 0;
}

/* ==========================================================================
   Footer — come warm
   ========================================================================== */

.ondo-footer {
  padding: clamp(84px, 12vh, 150px) clamp(20px, 6vw, 72px)
    clamp(96px, 14vh, 160px);
  text-align: center;
}

.ondo-footer__call {
  margin: 0;
  font-family: var(--ondo-font-display);
  font-weight: 400;
  font-size: clamp(2.4rem, 8vw, 5.2rem);
  line-height: 1.1;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--ondo-champagne);
}

.ondo-footer__callko {
  display: block;
  margin-top: 0.5rem;
  font-size: 0.32em;
  letter-spacing: 0.3em;
  text-transform: none;
  color: var(--ondo-champagne-dim);
}

.ondo-footer__rule {
  width: clamp(72px, 16vw, 150px);
  height: 1px;
  margin: 2.8rem auto;
  background: var(--ondo-vermeil);
}

.ondo-footer__address {
  margin: 0 0 2.4rem;
  font-style: normal;
  font-size: 0.95rem;
  line-height: 2;
  letter-spacing: 0.04em;
  color: var(--ondo-cream);
}

.ondo-footer__address :lang(ko) {
  color: var(--ondo-champagne-dim);
}

.ondo-footer__legal {
  margin: 0 0 2.2rem;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  color: var(--ondo-champagne-dim);
}

.ondo-footer__nav {
  margin: 0;
  font-size: 0.85rem;
  letter-spacing: 0.08em;
}

/* ==========================================================================
   Reveals — all pre-states gated behind .ondo-js
   ========================================================================== */

.ondo-js [data-reveal="fade"] {
  opacity: 0;
  transform: translateY(14px);
  transition:
    opacity var(--ondo-reveal-ms) var(--ondo-ease-air),
    transform var(--ondo-reveal-ms) var(--ondo-ease-air);
  will-change: opacity, transform;
}

.ondo-js [data-reveal="fade"].is-visible {
  opacity: 1;
  transform: none;
}

/* The collection's masked reveal: a couture wipe on the card's art, its
   text following one beat later. The stagger set by the observer arrives
   through --ondo-reveal-delay so children keep the same rhythm. */
.ondo-js [data-reveal="clip"] .ondo-card__art {
  clip-path: inset(0 100% 0 0);
  transition: clip-path 950ms var(--ondo-ease-couture);
  transition-delay: var(--ondo-reveal-delay, 0ms);
  will-change: clip-path;
}

.ondo-js [data-reveal="clip"].is-visible .ondo-card__art {
  clip-path: inset(0 0 0 0);
}

.ondo-js [data-reveal="clip"] .ondo-card__body {
  opacity: 0;
  transform: translateY(12px);
  transition:
    opacity 700ms var(--ondo-ease-air),
    transform 700ms var(--ondo-ease-air);
  transition-delay: calc(var(--ondo-reveal-delay, 0ms) + 220ms);
}

.ondo-js [data-reveal="clip"].is-visible .ondo-card__body {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity only
   ========================================================================== */

@keyframes ondo-hint {
  0%,
  100% {
    opacity: 0.45;
    transform: translateY(0);
  }
  50% {
    opacity: 0.85;
    transform: translateY(5px);
  }
}

/* ==========================================================================
   Reduced motion — everything settles into one composed, airy state:
   the wordmark rests open, reveals appear instantly, the refraction pane
   holds a single still frame (no rAF loop runs), nothing shimmers.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .ondo-js .ondo-hero__hint {
    animation: none;
  }

  .ondo-wordmark__ch {
    transform: none !important;
  }

  .ondo-js .ondo-bottle__pane.is-live {
    transition: none;
  }

  .ondo-js [data-reveal="fade"],
  .ondo-js [data-reveal="clip"] .ondo-card__body {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .ondo-js [data-reveal="clip"] .ondo-card__art {
    clip-path: none;
    transition: none;
  }

  .ondo-rail {
    scroll-behavior: auto;
  }
}
